export function readable(value, start) {
	return {
		subscribe: writable(value, start).subscribe
	};
}

#toggle() {
	if (this.opts.indeterminate.current) {
		this.opts.indeterminate.current = false;
		this.opts.checked.current = true;
	} else {
		this.opts.checked.current = !this.opts.checked.current;
	}
}

const unsubscribe = ctx.disableItems.subscribe((value) => {
  if (!value && initialDisabled) return;
  disabled = value;
});

const unsubscribe = selectedValues.subscribe((value) => {
  if (readonly) return;
  selected = value;
  if (!isInitialRender) {
    dispatch("change", value);
  }
});

const unsubscribe = selectedValue.subscribe((value) => {
  if (readonly) return;
  selected = value;
  if (!isInitialRender) {
    dispatch("change", value);
  }
});

function check_named_default_separate(actions) {
	if (actions.default && Object.keys(actions).length > 1) {
		throw new Error(
			'When using named actions, the default action cannot be used. See the docs for more info: https://svelte.dev/docs/kit/form-actions#named-actions'
		);
	}
}

export function action_json_redirect(redirect) {
	return action_json({
		type: 'redirect',
		status: redirect.status,
		location: redirect.location
	});
}

const change = async (direction) => {
  await changeTo(moveIndex(currentIndex, direction, switches.length));
};
